pub fn MLAY(cpu: &mut Cpu) {
    if cpu.reg.a != 0x03 {
        if cpu.reg.a < 0x04 {
            MLayGen(cpu);
            return;
        }
        MLayMask(cpu);
        return;
    }
    MLayXOR(cpu);
    return;
}

